onOptionChange:
{{
storeValue("deptReadyfa", false)
.then(() => storeValue("selectedDepartmentFA", null))
.then(() => storeValue("selectedPO", Select_FA.selectedOptionValue))
.then(() =>
  storeValue(
    "currentVersion",
    "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, function(c) {
      const r = Math.random() * 16 | 0;
      const v = c === "x" ? r : (r & 0x3 | 0x8);
      return v.toString(16);
    })
  )
)
.then(() => GetPOHFA.run())
.then(() => GetPODeliverablesFA.run())
.then(() => GetPOGroupTestsFA.run())
.then(() => GetPONREFA.run())
//.then(() => GetDepartmentSignOffFA.run())
.then(() => GetActionsFA.run())

.then(() => storeValue("answers", {}))
.then(() => storeValue("originalAnswers", {}))
.then(() => storeValue("deptReady", true))
.catch((err) => {
  console.error("Select_FA failed:", err);
  showAlert("Failed to load PO data", "error");
  storeValue("deptReady", false);
})
}}
